/**
 * Interface discovery — consumer side (work doc #17, mirrors the consumer half
 * of `RNS/Discovery.py`).
 *
 * Covers: aspect name-hash filtering, the LXMF stamp round-trip at discovery's
 * cheap work factor, msgpack `info`-dict parsing field-for-field against a
 * fixture generated by the Python reference, the generated `config_entry`
 * string, persistence via a KV storage adapter, the EventTarget surface, and
 * the freshness/authorization logic in `listDiscoveredInterfaces`.
 */
import assert from "node:assert";
import fs from "node:fs";
import test from "node:test";
import { fileURLToPath } from "node:url";
import { Destination } from "../../src/core/destination.js";
import { Identity } from "../../src/core/identity.js";
import { DestType, Packet, PacketType } from "../../src/core/packet.js";
import {
  ACCEPTED_INTERFACE_TYPES,
  ASPECT,
  aspectNameHash,
  buildConfigEntry,
  buildDiscoveryAppData,
  DEFAULT_STAMP_VALUE,
  DISCOVERABLE_TYPES,
  FLAG_ENCRYPTED,
  generateDiscoveryStamp,
  InterfaceDiscovery,
  isHostname,
  isIpAddress,
  parseDiscoveryAnnounce,
  sanitizeName,
  WORKBLOCK_EXPAND_ROUNDS,
} from "../../src/transport/discovery.js";
import { TransportCore } from "../../src/transport/transport.js";
import { fromHex, toHex } from "../../src/utils/encoding.js";
import { MicroMsgPack } from "../../src/utils/msgpack.js";

const here = fileURLToPath(new URL(".", import.meta.url));
const FIXTURE_PATH = `${here}../fixtures/discovery_tcp.json`;

/** Reads the Python-generated TCP discovery fixture. */
function loadFixture() {
  return JSON.parse(fs.readFileSync(FIXTURE_PATH, "utf8"));
}

/**
 * Builds a complete discovery `info` Map (integer keys, matching Python's wire
 * format) with the optional geo fields defaulted to `nil`, the way Python's
 * `InterfaceAnnouncer.get_interface_announce_data` always emits them.
 * @param {Object} p
 * @returns {Map<number, any>}
 */
function makeInfo({
  type = "TCPServerInterface",
  transport = true,
  transportId,
  name,
  reachableOn,
  port,
  latitude = null,
  longitude = null,
  height = null,
}) {
  return new Map([
    [0x00, type],
    [0x01, transport],
    [0xfe, transportId],
    [0xff, name],
    [0x03, latitude],
    [0x04, longitude],
    [0x05, height],
    [0x02, reachableOn],
    [0x06, port],
  ]);
}

/** In-memory KV storage adapter implementing the work-doc-#16 interface. */
class MemoryStorage {
  constructor() {
    /** @type {Map<string, Map<string, Uint8Array>>} */
    this.namespaces = new Map();
  }
  /** @param {string} ns */
  #ns(ns) {
    let m = this.namespaces.get(ns);
    if (!m) {
      m = new Map();
      this.namespaces.set(ns, m);
    }
    return m;
  }
  async loadKey() {
    return null;
  }
  async saveKey() {}
  async get(ns, key) {
    return this.#ns(ns).get(key) ?? null;
  }
  async set(ns, key, value) {
    this.#ns(ns).set(key, value);
  }
  async delete(ns, key) {
    this.#ns(ns).delete(key);
  }
  async keys(ns) {
    return [...this.#ns(ns).keys()];
  }
}

