test("sanitizeName mirrors Python's sanitize_name", () => {
  assert.strictEqual(sanitizeName("Example Node"), "Example Node");
  assert.strictEqual(sanitizeName("  Leading"), "Leading");
  // Non-ASCII stripped, multi-space collapse.
  assert.strictEqual(sanitizeName("Hello   World"), "Hello World");
  assert.strictEqual(sanitizeName("Hello     World"), "Hello World");
  // Leading/trailing punctuation trimmed (only alphanumerics survive at edges).
  assert.strictEqual(sanitizeName("!!!Node!!!"), "Node");
  // Closing ")" is allowed at the trailing edge.
  assert.strictEqual(sanitizeName("Node (EU)"), "Node (EU)");
  assert.strictEqual(sanitizeName(null), null);
  assert.strictEqual(sanitizeName(""), null);
  assert.strictEqual(sanitizeName(undefined), null);
});

test("isIpAddress / isHostname port Python's ipaddress + hostname checks", () => {
  assert.ok(isIpAddress("127.0.0.1"));
  assert.ok(isIpAddress("8.8.8.8"));
  assert.ok(isIpAddress("::1"));
  assert.ok(isIpAddress("2001:db8::1"));
  assert.ok(isIpAddress("::"));
  assert.ok(!isIpAddress("999.1.1.1"));
  assert.ok(!isIpAddress("1.2.3"));
  assert.ok(!isIpAddress("not an ip"));

  assert.ok(isHostname("example.com"));
  assert.ok(isHostname("node.example.reticulum.network"));
  assert.ok(isHostname("a.b.c.d"));
  // Trailing all-numeric label looks like an IP, not a hostname.
  assert.ok(!isHostname("1.2.3.4"));
  assert.ok(!isHostname(""));
  assert.ok(!isHostname("a".repeat(300)));
});

// ---------------------------------------------------------------------
// Stamp round-trip + app_data assembly (producer primitives)
// ---------------------------------------------------------------------

test("a discovery stamp validates at the required cost and is rejected when tampered", async () => {
  const transportId = crypto.getRandomValues(new Uint8Array(16));
  const info = makeInfo({
    transportId,
    name: "Test Node",
    reachableOn: "example.com",
    port: 42424,
  });

  // generateDiscoveryStamp alone proves the producer path mints a stamp that
  // meets the required cost (separate random search from buildDiscoveryAppData).
  const [, genValue] = /** @type {[Uint8Array, number]} */ (
    await generateDiscoveryStamp(info, 8, WORKBLOCK_EXPAND_ROUNDS)
  );
  assert.ok(genValue >= 8, `achieved value ${genValue} should meet cost 8`);

  // Build the full app_data once and derive every assertion from it, so the
  // stamp the parser sees is the same one baked into the blob.
  const appData = await buildDiscoveryAppData(info, { stampCost: 8 });
  // Layout: flags(1) || packed || stamp(32). flags == 0 (no encryption).
  assert.strictEqual(appData[0], 0);
  assert.strictEqual(appData.length, 1 + (appData.length - 1 - 32) + 32);

  // A fresh Identity to stand in for the announced identity.
  const announced = await Identity.generate();
  const parsed = await parseDiscoveryAnnounce(appData, announced, {
    requiredValue: 8,
  });
  assert.ok(parsed, "parser should accept a freshly minted stamp");
  assert.strictEqual(parsed?.name, "Test Node");
  assert.strictEqual(parsed?.type, "TCPServerInterface");
  assert.ok(
    /** @type {number} */ (parsed?.value) >= 8,
    `parsed value ${parsed?.value} should meet cost 8`,
  );

  // Tamper one stamp byte → the parser must reject it.
  const tampered = new Uint8Array(appData);
  tampered[tampered.length - 1] ^= 0xff;
  const rejected = await parseDiscoveryAnnounce(tampered, announced, {
    requiredValue: 8,
  });
  assert.strictEqual(rejected, null, "tampered stamp must be rejected");
});

test("parseDiscoveryAnnounce returns null for too-short app_data", async () => {
  const announced = await Identity.generate();
  // STAMP_SIZE + 1 = 33 bytes is the minimum; 5 bytes is well below.
  const short = new Uint8Array(5);
  assert.strictEqual(await parseDiscoveryAnnounce(short, announced), null);
});

test("parseDiscoveryAnnounce rejects an unauthorized discovery source", async () => {
  const transportId = crypto.getRandomValues(new Uint8Array(16));
  const info = makeInfo({
    transportId,
    name: "Auth Test",
    reachableOn: "example.com",
    port: 42424,
  });
  const appData = await buildDiscoveryAppData(info, { stampCost: 8 });
  const announced = await Identity.generate();

  // Allow-list contains a *different* identity hash → reject.
  const other = await Identity.generate();
  const parsed = await parseDiscoveryAnnounce(appData, announced, {
    requiredValue: 8,
    discoverySources: [other.identityHash],
  });
  assert.strictEqual(parsed, null);
});

// ---------------------------------------------------------------------
// Python interop: parse a fixture produced by RNS/Discovery.py
// ---------------------------------------------------------------------

test("parses a Python-generated discovery announce byte-for-byte (interop)", async () => {
  const fx = loadFixture();
  const appData = fromHex(fx.app_data_hex);
  const announced = await Identity.fromPublicKey(
    fromHex(fx.announced_identity_pub_hex),
  );
  // Sanity: our Identity reconstruction matches the Python identity hash.
  assert.strictEqual(
    toHex(announced.identityHash),
    fx.announced_identity_hash_hex,
  );

  const info = await parseDiscoveryAnnounce(appData, announced, {
    requiredValue: fx.required_value,
    hops: fx.parsed.hops,
  });
  assert.ok(info, "fixture stamp must validate");

  const expected = fx.parsed;
  assert.strictEqual(info?.type, expected.type);
  assert.strictEqual(info?.transport, expected.transport);
  assert.strictEqual(info?.name, expected.name);
  assert.strictEqual(info?.value, expected.value);
  assert.strictEqual(info?.transportIdHex, expected.transport_id);
  assert.strictEqual(info?.networkIdHex, expected.network_id);
  assert.strictEqual(info?.hops, expected.hops);
  assert.strictEqual(info?.latitude, expected.latitude);
  assert.strictEqual(info?.longitude, expected.longitude);
  assert.strictEqual(info?.height, expected.height);
  assert.strictEqual(info?.reachable_on, expected.reachable_on);
  assert.strictEqual(info?.port, expected.port);
  assert.strictEqual(info?.config_entry, expected.config_entry);
  // discovery_hash: Python emits 32 raw bytes; we emit the hex of the same.
  assert.strictEqual(
    info?.discoveryHashHex,
    expected.discovery_hash.__bytes_hex__,
  );
  // stamp: same 32 bytes.
  assert.strictEqual(
    toHex(/** @type {Uint8Array} */ (info?.stamp)),
    expected.stamp.__bytes_hex__,
  );
});

